   ["Gives your pet a 100% chance to gain a 30% attack speed increase for 8 sec after dealing a critical strike."] = "Evcil hayvanına (pet) kritik vuruş yaptıktan sonra 8 sn boyunca %30 saldırı hızı artışı kazanmak için %100 şans verir.",
   ["Gives your pet a 20% chance to gain a 30% attack speed increase for 8 sec after dealing a critical strike."] = "Evcil hayvanına (pet) kritik vuruş yaptıktan sonra 8 sn boyunca %30 saldırı hızı artışı kazanmak için %20 şans verir.",
   ["Gives your pet a 40% chance to gain a 30% attack speed increase for 8 sec after dealing a critical strike."] = "Evcil hayvanına (pet) kritik vuruş yaptıktan sonra 8 sn boyunca %30 saldırı hızı artışı kazanmak için %40 şans verir.",
   ["Gives your pet a 60% chance to gain a 30% attack speed increase for 8 sec after dealing a critical strike."] = "Evcil hayvanına (pet) kritik vuruş yaptıktan sonra 8 sn boyunca %30 saldırı hızı artışı kazanmak için %60 şans verir.",
   ["Gives your pet a 80% chance to gain a 30% attack speed increase for 8 sec after dealing a critical strike."] = "Evcil hayvanına (pet) kritik vuruş yaptıktan sonra 8 sn boyunca %30 saldırı hızı artışı kazanmak için %80 şans verir.",
   ["Gives your Shadow Bolt, Shadowburn, Chaos Bolt, Soul Fire, Incinerate, Searing Pain and Conflagrate spells a 10% chance to return health equal to 20% of the damage caused."] = "Shadow Bolt, Shadowburn, Chaos Bolt, Soul Fire, Incinerate, Searing Pain ve Conflagrate büyülerine, verilen hasarın %20'si kadar can geri kazandırma şansı %10 verir.",
   ["Gives your Shadow Bolt, Shadowburn, Chaos Bolt, Soul Fire, Incinerate, Searing Pain and Conflagrate spells a 20% chance to return health equal to 20% of the damage caused."] = "Shadow Bolt, Shadowburn, Chaos Bolt, Soul Fire, Incinerate, Searing Pain ve Conflagrate büyülerine, verilen hasarın %20'si kadar can geri kazandırma şansı %20 verir.",
   ["Gives your Shadow Bolt, Shadowburn, Chaos Bolt, Soul Fire, Incinerate, Searing Pain and Conflagrate spells a 30% chance to return health equal to 20% of the damage caused."] = "Shadow Bolt, Shadowburn, Chaos Bolt, Soul Fire, Incinerate, Searing Pain ve Conflagrate büyülerine, verilen hasarın %20'si kadar can geri kazandırma şansı %30 verir.",
   ["Gives your Shield Bash and Heroic Throw abilities a 100% chance to silence the target for 3 sec and increases the damage of your Shield Slam ability by 10%."] = "Shield Bash ve Heroic Throw yeteneklerine, hedefi 3 sn boyunca susturma şansını %100 verir ve Shield Slam yeteneğinin hasarını %10 artırır.",
   ["Gives your Shield Bash and Heroic Throw abilities a 50% chance to silence the target for 3 sec and increases the damage of your Shield Slam ability by 5%."] = "Shield Bash ve Heroic Throw yeteneklerine, hedefi 3 sn boyunca susturma şansını %50 verir ve Shield Slam yeteneğinin hasarını %5 artırır.",
   ["Gives your successful off-hand melee attacks a 20% chance to generate 12 Energy."] = "Başarılı ikincil el yakın dövüş saldırılarına 12 Enerji üretme şansını %20 verir.",
   ["Gives your successful off-hand melee attacks a 20% chance to generate 15 Energy."] = "Başarılı ikincil el yakın dövüş saldırılarına 15 Enerji üretme şansını %20 verir.",
   ["Gives your successful off-hand melee attacks a 20% chance to generate 3 Energy."] = "Başarılı ikincil el yakın dövüş saldırılarına 3 Enerji üretme şansını %20 verir.",
   ["Gives your successful off-hand melee attacks a 20% chance to generate 6 Energy."] = "Başarılı ikincil el yakın dövüş saldırılarına 6 Enerji üretme şansını %20 verir.",
   ["Gives your successful off-hand melee attacks a 20% chance to generate 9 Energy."] = "Başarılı ikincil el yakın dövüş saldırılarına 9 Enerji üretme şansını %20 verir.",
   ["Grants 10% spell haste for your next spell after casting Power Word: Shield, and increases the amount absorbed by your Power Word: Shield equal to 16% of your spell power."] = "Power Word: Shield yaptıktan sonra bir sonraki büyün için %10 büyü hızlanması verir ve Power Word: Shield'in emdiği miktarı büyü gücünün %16'sı kadar artırır.",
   ["Grants 15% spell haste for your next spell after casting Power Word: Shield, and increases the amount absorbed by your Power Word: Shield equal to 24% of your spell power."] = "Power Word: Shield yaptıktan sonra bir sonraki büyün için %15 büyü hızlanması verir ve Power Word: Shield'in emdiği miktarı büyü gücünün %24'ü kadar artırır.",
   ["Grants 160% additional armor contribution from cloth and leather items while in Travel Form or while not shapeshifted, increases the damage reduction granted by your Barkskin spell by 10% and reduces the chance your Barkskin is dispelled by 70%."] = "Travel Form'dayken veya şekil değiştirmemişken kumaş ve deri eşyalardan %160 ek zırh katkısı sağlar, Barkskin büyünün verdiği hasar azaltmasını %10 artırır ve Barkskin'inin dağıtılma şansını %70 azaltır.",
   ["Grants 20% spell haste for your next spell after casting Power Word: Shield, and increases the amount absorbed by your Power Word: Shield equal to 32% of your spell power."] = "Power Word: Shield yaptıktan sonra bir sonraki büyün için %20 büyü hızlanması verir ve Power Word: Shield'in emdiği miktarı büyü gücünün %32'si kadar artırır.",
   ["Grants 25% spell haste for your next spell after casting Power Word: Shield, and increases the amount absorbed by your Power Word: Shield equal to 40% of your spell power."] = "Power Word: Shield yaptıktan sonra bir sonraki büyün için %25 büyü hızlanması verir ve Power Word: Shield'in emdiği miktarı büyü gücünün %40'ı kadar artırır.",
   ["Grants 5% spell haste for your next spell after casting Power Word: Shield, and increases the amount absorbed by your Power Word: Shield equal to 8% of your spell power."] = "Power Word: Shield yaptıktan sonra bir sonraki büyün için %5 büyü hızlanması verir ve Power Word: Shield'in emdiği miktarı büyü gücünün %8'i kadar artırır.",
   ["Grants 80% additional armor contribution from cloth and leather items while in Travel Form or while not shapeshifted, increases the damage reduction granted by your Barkskin spell by 5% and reduces the chance your Barkskin is dispelled by 35%."] = "Travel Form'dayken veya şekil değiştirmemişken kumaş ve deri eşyalardan %80 ek zırh katkısı sağlar, Barkskin büyünün verdiği hasar azaltmasını %5 artırır ve Barkskin'inin dağıtılma şansını %35 azaltır.",
   ["Grants an effect which lasts while the Druid is within the respective shapeshift form. Bear Form - Increases physical damage by 2%. Cat Form - Increases critical strike chance by 2%. Moonking Form - Increases spell damage by 2%. Tree of Life Form - Increases healing by 2%."] = "Druid ilgili şekil değiştirme formundayken süren bir etki sağlar. Bear Form - Fiziksel hasarı %2 artırır. Cat Form - Kritik vurma şansını %2 artırır. Moonkin Form - Büyü hasarını %2 artırır. Tree of Life Form - İyileştirmeyi %2 artırır.",
   ["Grants an effect which lasts while the Druid is within the respective shapeshift form. Bear Form - Increases physical damage by 4%. Cat Form - Increases critical strike chance by 4%. Moonking Form - Increases spell damage by 4%. Tree of Life Form - Increases healing by 4%."] = "Druid ilgili şekil değiştirme formundayken süren bir etki sağlar. Bear Form - Fiziksel hasarı %4 artırır. Cat Form - Kritik vurma şansını %4 artırır. Moonkin Form - Büyü hasarını %4 artırır. Tree of Life Form - İyileştirmeyi %4 artırır.",
   ["Grants both the Warlock and the summoned demon an effect as long as that demon is active. Imp - Increases your Fire damage by 1%, and increases the critical effect chance of your Fire spells by 1%. Voidwalker - Reduces Physical damage taken by 2%. Succubus - Increases your Shadow damage by 1%, and increases the critical effect chance of your Shadow spells by 1%. Felhunter - Reduces all spell damage taken by 2%. Felguard - Increases all damage done by 1%, and reduces all damage taken by 1%."] = "Hem Warlock'a hem de çağırdığı iblise, o iblis aktif olduğu sürece bir etki sağlar. Imp - Ateş hasarını %1 artırır ve Ateş büyülerinin kritik etki şansını %1 artırır. Voidwalker - Alınan Fiziksel hasarı %2 azaltır. Succubus - Gölge hasarını %1 artırır ve Gölge büyülerinin kritik etki şansını %1 artırır. Felhunter - Alınan tüm büyü hasarını %2 azaltır. Felguard - Verilen tüm hasarı %1 artırır ve alınan tüm hasarı %1 azaltır.",
   ["Grants both the Warlock and the summoned demon an effect as long as that demon is active. Imp - Increases your Fire damage by 2%, and increases the critical effect chance of your Fire spells by 2%. Voidwalker - Reduces Physical damage taken by 4%. Succubus - Increases your Shadow damage by 2%, and increases the critical effect chance of your Shadow spells by 2%. Felhunter - Reduces all spell damage taken by 4%. Felguard - Increases all damage done by 2%, and reduces all damage taken by 2%."] = "Hem Warlock'a hem de çağırdığı iblise, o iblis aktif olduğu sürece bir etki sağlar. Imp - Ateş hasarını %2 artırır ve Ateş büyülerinin kritik etki şansını %2 artırır. Voidwalker - Alınan Fiziksel hasarı %4 azaltır. Succubus - Gölge hasarını %2 artırır ve Gölge büyülerinin kritik etki şansını %2 artırır. Felhunter - Alınan tüm büyü hasarını %4 azaltır. Felguard - Verilen tüm hasarı %2 artırır ve alınan tüm hasarı %2 azaltır.",
   ["Grants both the Warlock and the summoned demon an effect as long as that demon is active. Imp - Increases your Fire damage by 3%, and increases the critical effect chance of your Fire spells by 3%. Voidwalker - Reduces Physical damage taken by 6%. Succubus - Increases your Shadow damage by 3%, and increases the critical effect chance of your Shadow spells by 3%. Felhunter - Reduces all spell damage taken by 6%. Felguard - Increases all damage done by 3%, and reduces all damage taken by 3%."] = "Hem Warlock'a hem de çağırdığı iblise, o iblis aktif olduğu sürece bir etki sağlar. Imp - Ateş hasarını %3 artırır ve Ateş büyülerinin kritik etki şansını %3 artırır. Voidwalker - Alınan Fiziksel hasarı %6 azaltır. Succubus - Gölge hasarını %3 artırır ve Gölge büyülerinin kritik etki şansını %3 artırır. Felhunter - Alınan tüm büyü hasarını %6 azaltır. Felguard - Verilen tüm hasarı %3 artırır ve alınan tüm hasarı %3 azaltır.",
   ["Grants both the Warlock and the summoned demon an effect as long as that demon is active. Imp - Increases your Fire damage by 4%, and increases the critical effect chance of your Fire spells by 4%. Voidwalker - Reduces Physical damage taken by 8%. Succubus - Increases your Shadow damage by 4%, and increases the critical effect chance of your Shadow spells by 4%. Felhunter - Reduces all spell damage taken by 8%. Felguard - Increases all damage done by 4%, and reduces all damage taken by 4%."] = "Hem Warlock'a hem de çağırdığı iblise, o iblis aktif olduğu sürece bir etki sağlar. Imp - Ateş hasarını %4 artırır ve Ateş büyülerinin kritik etki şansını %4 artırır. Voidwalker - Alınan Fiziksel hasarı %8 azaltır. Succubus - Gölge hasarını %4 artırır ve Gölge büyülerinin kritik etki şansını %4 artırır. Felhunter - Alınan tüm büyü hasarını %8 azaltır. Felguard - Verilen tüm hasarı %4 artırır ve alınan tüm hasarı %4 azaltır.",
   ["Grants both the Warlock and the summoned demon an effect as long as that demon is active. Imp - Increases your Fire damage by 5%, and increases the critical effect chance of your Fire spells by 5%. Voidwalker - Reduces Physical damage taken by 10%. Succubus - Increases your Shadow damage by 5%, and increases the critical effect chance of your Shadow spells by 5%. Felhunter - Reduces all spell damage taken by 10%. Felguard - Increases all damage done by 5%, and reduces all damage taken by 5%."] = "Hem Warlock'a hem de çağırdığı iblise, o iblis aktif olduğu sürece bir etki sağlar. Imp - Ateş hasarını %5 artırır ve Ateş büyülerinin kritik etki şansını %5 artırır. Voidwalker - Alınan Fiziksel hasarı %10 azaltır. Succubus - Gölge hasarını %5 artırır ve Gölge büyülerinin kritik etki şansını %5 artırır. Felhunter - Alınan tüm büyü hasarını %10 azaltır. Felguard - Verilen tüm hasarı %5 artırır ve alınan tüm hasarı %5 azaltır.",
   ["Grants the periodic damage from your Corruption and Unstable Affliction spells the ability to critically hit for 100% increased damage, and increases the critical strike damage bonus of your Haunt spell by 100%."] = "Corruption ve Unstable Affliction büyülerinin periyodik hasarına %100 artırılmış hasarla kritik vurma yeteneği kazandırır ve Haunt büyünün kritik vurma hasar bonusunu %100 artırır.",
   ["Grants the periodic damage from your Lacerate and Rip abilities the ability to critically hit."] = "Lacerate ve Rip yeteneklerinden gelen periyodik hasara kritik vurma yeteneği kazandırır.",
   ["Grants the target of your Lay on Hands spell 10% reduced physical damage taken for 15 sec. In addition, the cooldown for your Lay on Hands spell is reduced by 2 min."] = "Lay on Hands büyünün hedefine 15 sn boyunca %10 azaltılmış fiziksel hasar alımı sağlar. Buna ek olarak, Lay on Hands büyünün bekleme süresi 2 dk azalır.",
   ["Grants the target of your Lay on Hands spell 20% reduced physical damage taken for 15 sec. In addition, the cooldown for your Lay on Hands spell is reduced by 4 min."] = "Lay on Hands büyünün hedefine 15 sn boyunca %20 azaltılmış fiziksel hasar alımı sağlar. Buna ek olarak, Lay on Hands büyünün bekleme süresi 4 dk azalır.",
   ["Grants the Warlock's summoned demon Empowerment. Imp - Increases the Imp's spell critical strike chance by 20% for 30 sec. Voidwalker - Increases the Voidwalker's health by 20%, and its threat generated from spells and attacks by 20% for 20 sec. Succubus - Instantly vanishes, causing the Succubus to go into an improved Invisibility state. The vanish effect removes all stuns, snares and movement impairing effects from the Succubus. Felhunter - Dispels all magical effects from the Felhunter. Felguard - Increases the Felguard's attack speed by 20% and breaks all stun, snare and movement impairing effects and makes your Felguard immune to them for 15 sec."] = "Warlock'un çağırdığı iblise Empowerment kazandırır. Imp - Imp'in büyü kritik vurma şansını 30 sn boyunca %20 artırır. Voidwalker - Voidwalker'ın canını %20, büyülerden ve saldırılardan ürettiği tehdidi 20 sn boyunca %20 artırır. Succubus - Anında ortadan kaybolur ve Succubus'u gelişmiş bir Invisibility durumuna sokar. Kaybolma etkisi Succubus'tan tüm sersemletme, yavaşlatma ve hareket kısıtlayıcı etkileri kaldırır. Felhunter - Felhunter'dan tüm büyülü etkileri temizler. Felguard - Felguard'ın saldırı hızını %20 artırır, tüm sersemletme, yavaşlatma ve hareket kısıtlayıcı etkileri kırar ve Felguard'ını 15 sn boyunca bunlara karşı bağışık yapar.",
   ["Grants your pet 25% haste for 30 sec and heals it for 60% of its health over the duration."] = "Evcil hayvanına 30 sn boyunca %25 hız kazandırır ve onu bu süre boyunca sağlığının %60'ı kadar iyileştirir.",
   ["Hammer the current target and up to 2 additional nearby targets, causing 4 times your main hand damage per second as Holy damage."] = "Mevcut hedefi ve yakındaki en fazla 2 ek hedefi çekiçler, saniyede ana el hasarının 4 katı kadar Kutsal hasarı verir.",
   ["Hastens your spellcasting, increasing spell casting speed by 20% and reduces the pushback suffered from damaging attacks while casting by 100%. Lasts 20 sec."] = "Büyü okumanı hızlandırır; büyü okuma hızını %20 artırır ve büyü yaparken hasar veren saldırılardan gelen geri itilmeyi %100 azaltır. 20 sn sürer.",
   ["Heals a friendly target for 639 to 691 and another 665 over 15 sec. Your next Chain Heal cast on that primary target within 15 sec will consume the healing over time effect and increase the amount of the Chain Heal by 25%."] = "Dost bir hedefi 639 ila 691 iyileştirir ve 15 sn boyunca ek olarak 665 iyileştirir. Bu ana hedefe 15 sn içinde yapılan sonraki Chain Heal, süre içindeki iyileştirme etkisini tüketir ve Chain Heal miktarını %25 artırır.",
   ["Heals up to 5 friendly party or raid members within 15 yards of the target for 343 to 379."] = "Hedefin 15 metre içindeki 5 adede kadar dost grup veya akın üyesini 343 ila 379 iyileştirir.",
   ["Heals up to 5 friendly party or raid members within 15 yards of the target for 686 over 7 sec. The amount healed is applied quickly at first, and slows down as the Wild Growth reaches its full duration."] = "Hedefin 15 metre içindeki en fazla 5 dost grup veya akın üyesini 7 sn boyunca 686 iyileştirir. İyileştirilen miktar önce hızlıca uygulanır ve Wild Growth tam süresine ulaştıkça yavaşlar.",
   ["Heals you for up to 2% of your maximum health whenever you kill a target that yields experience or honor."] = "Deneyim ya da onur veren bir hedefi öldürdüğünde seni maksimum sağlığının %2'sine kadar iyileştirir.",
   ["Heals you for up to 4% of your maximum health whenever you kill a target that yields experience or honor."] = "Deneyim ya da onur veren bir hedefi öldürdüğünde seni maksimum sağlığının %4'üne kadar iyileştirir.",
   ["Heals you for up to 6% of your maximum health whenever you kill a target that yields experience or honor."] = "Deneyim ya da onur veren bir hedefi öldürdüğünde seni maksimum sağlığının %6'sına kadar iyileştirir.",
   ["Hurls a holy shield at the enemy, dealing 440+0.07* HolP +0.07* AP to 536+0.07* HolP +0.07* AP Holy damage, Dazing them and then jumping to additional nearby enemies. Affects 3 total targets. Lasts 10 sec."] = "Düşmana kutsal bir kalkan fırlatır, 440+0.07*HolP+0.07*AP ila 536+0.07*HolP+0.07*AP Kutsal hasarı verir, onları sersemletir ve ardından yakındaki ek düşmanlara sıçrar. Toplam 3 hedefi etkiler. 10 sn sürer.",
   ["Hurls an immense fiery boulder that causes 141 to 187 Fire damage and an additional 56 Fire damage over 12 sec."] = "Devasa, alevli bir kaya fırlatır; 141 ila 187 Ateş hasarı ve 12 sn boyunca ek 56 Ateş hasarı verir.",
   ["If Wyvern Sting is dispelled, the dispeller is also afflicted by Wyvern Sting lasting 16% of the duration remaining, and increases all damage done by you on targets afflicted by your Serpent Sting by 1%."] = "Wyvern Sting dağıtılırsa, dağıtan kişi de kalan sürenin %16'sı kadar süren Wyvern Sting ile etkilenir ve senin Serpent Sting ile etkilenmiş hedeflere verdiğin tüm hasar %1 artar.",
   ["If Wyvern Sting is dispelled, the dispeller is also afflicted by Wyvern Sting lasting 25% of the duration remaining, and increases all damage done by you on targets afflicted by your Serpent Sting by 2%."] = "Wyvern Sting dağıtılırsa, dağıtan kişi de kalan sürenin %25'i kadar süren Wyvern Sting ile etkilenir ve senin Serpent Sting ile etkilenmiş hedeflere verdiğin tüm hasar %2 artar.",
   ["If Wyvern Sting is dispelled, the dispeller is also afflicted by Wyvern Sting lasting 50% of the duration remaining, and increases all damage done by you on targets afflicted by your Serpent Sting by 3%."] = "Wyvern Sting dağıtılırsa, dağıtan kişi de kalan sürenin %50'si kadar süren Wyvern Sting ile etkilenir ve senin Serpent Sting ile etkilenmiş hedeflere verdiğin tüm hasar %3 artar.",
   ["Improves your chance to get a critical strike with all spells and attacks by 1%."] = "Tüm büyü ve saldırılarla kritik vuruş yapma şansını %1 artırır.",
   ["Improves your chance to get a critical strike with all spells and attacks by 2%."] = "Tüm büyü ve saldırılarla kritik vuruş yapma şansını %2 artırır.",
   ["Improves your chance to get a critical strike with all spells and attacks by 3%."] = "Tüm büyü ve saldırılarla kritik vuruş yapma şansını %3 artırır.",
   ["Improves your chance to get a critical strike with all spells and attacks by 4%."] = "Tüm büyü ve saldırılarla kritik vuruş yapma şansını %4 artırır.",
   ["Improves your chance to get a critical strike with all spells and attacks by 5%."] = "Tüm büyü ve saldırılarla kritik vuruş yapma şansını %5 artırır.",
   ["In addition to the normal effect, your Judgement spells will also increase the critical strike chance of all attacks made against that target by an additional 1%."] = "Normal etkiye ek olarak, Judgement büyülerin o hedefe yapılan tüm saldırıların kritik vurma şansını ayrıca %1 artırır.",
   ["In addition to the normal effect, your Judgement spells will also increase the critical strike chance of all attacks made against that target by an additional 2%."] = "Normal etkiye ek olarak, Judgement büyülerin o hedefe yapılan tüm saldırıların kritik vurma şansını ayrıca %2 artırır.",
   ["In addition to the normal effect, your Judgement spells will also increase the critical strike chance of all attacks made against that target by an additional 3%."] = "Normal etkiye ek olarak, Judgement büyülerin o hedefe yapılan tüm saldırıların kritik vurma şansını ayrıca %3 artırır.",
   ["Increases all attributes by 2%, reduces the chance you'll be critically hit by melee attacks by 2%, and increases your armor contribution from cloth and leather items in Bear Form and Dire Bear Form by 11%."] = "Tüm özellikleri %2 artırır, yakın dövüş saldırılarıyla kritik vurulma şansını %2 azaltır ve Bear Form ile Dire Bear Form'da kumaş ve deri eşyalardan gelen zırh katkını %11 artırır.",
   ["Increases all attributes by 4%, reduces the chance you'll be critically hit by melee attacks by 4%, and increases your armor contribution from cloth and leather items in Bear Form and Dire Bear Form by 22%."] = "Tüm özellikleri %4 artırır, yakın dövüş saldırılarıyla kritik vurulma şansını %4 azaltır ve Bear Form ile Dire Bear Form'da kumaş ve deri eşyalardan gelen zırh katkını %22 artırır.",
   ["Increases all attributes by 6%, reduces the chance you'll be critically hit by melee attacks by 6%, and increases your armor contribution from cloth and leather items in Bear Form and Dire Bear Form by 33%."] = "Tüm özellikleri %6 artırır, yakın dövüş saldırılarıyla kritik vurulma şansını %6 azaltır ve Bear Form ile Dire Bear Form'da kumaş ve deri eşyalardan gelen zırh katkını %33 artırır.",
   ["Increases all damage caused by 1% and all damage caused against Humanoids, Demons, Undead and Elementals by an additional 1%."] = "Verilen tüm hasarı %1 ve İnsansılar, İblisler, Hortlaklar ve Elementallere karşı verilen tüm hasarı ayrıca %1 artırır.",
   ["Increases all damage caused by 2% and all damage caused against Humanoids, Demons, Undead and Elementals by an additional 2%."] = "Verilen tüm hasarı %2 ve İnsansılar, İblisler, Hortlaklar ve Elementallere karşı verilen tüm hasarı ayrıca %2 artırır.",
   ["Increases all damage caused by 2%."] = "Verilen tüm hasarı %2 artırır.",
   ["Increases all damage caused by 3% and all damage caused against Humanoids, Demons, Undead and Elementals by an additional 3%."] = "Verilen tüm hasarı %3 ve İnsansılar, İblisler, Hortlaklar ve Elementallere karşı verilen tüm hasarı ayrıca %3 artırır.",
   ["Increases all damage caused by 4%."] = "Verilen tüm hasarı %4 artırır.",
   ["Increases all damage you deal by 10% and while your pet is under the effects of Bestial Wrath, you also go into a rage causing 10% additional damage and reducing mana costs of all spells by 50% for 10 sec. While enraged, you do not feel pity or remorse or fear and you cannot be stopped unless killed."] = "Verdiğin tüm hasarı %10 artırır ve evcil hayvanın (pet) Bestial Wrath etkisi altındayken sen de bir öfkeye girersin; 10 sn boyunca %10 ek hasar verir ve tüm büyülerin mana maliyetini %50 azaltır. Öfkeliyken acıma, pişmanlık veya korku hissetmezsin ve öldürülmedikçe durdurulamazsın.",
   ["Increases all damage you deal when a one-handed melee weapon is equipped by 10%."] = "Tek elli bir yakın dövüş silahı kuşanıldığında verdiğin tüm hasarı %10 artırır.",
   ["Increases all damage you deal when a one-handed melee weapon is equipped by 4%."] = "Tek elli bir yakın dövüş silahı kuşanıldığında verdiğin tüm hasarı %4 artırır.",
