   ["Reduces all spell damage taken by 8%."] = "Alınan tüm büyü hasarını %8 azaltır.",
   ["Reduces damage taken by the target of your Intervene ability by 15% for 6 sec."] = "Intervene yeteneğinin hedefinin aldığı hasarı 6 sn boyunca %15 azaltır.",
   ["Reduces damage taken by the target of your Intervene ability by 30% for 6 sec."] = "Intervene yeteneğinin hedefinin aldığı hasarı 6 sn boyunca %30 azaltır.",
   ["Reduces damage taken while affected by Stun and Fear effects by 15%."] = "Stun ve Fear etkilerinden etkilenirken alınan hasarı %15 azaltır.",
