   ["Reduces the cast time of your Ghost Wolf spell by 2 sec."] = "Ghost Wolf büyünün okuma süresini 2 sn azaltır.",
   ["Reduces the cast time of your Healing Touch spell by 0.1 sec and increases the damage you deal with physical attacks in all forms by 2%."] = "Healing Touch büyünün okuma süresini 0.1 sn azaltır ve tüm formlarda fiziksel saldırılarla verdiğin hasarı %2 artırır.",
   ["Reduces the cast time of your Healing Touch spell by 0.2 sec and increases the damage you deal with physical attacks in all forms by 4%."] = "Healing Touch büyünün okuma süresini 0.2 sn azaltır ve tüm formlarda fiziksel saldırılarla verdiğin hasarı %4 artırır.",
   ["Reduces the cast time of your Healing Touch spell by 0.3 sec and increases the damage you deal with physical attacks in all forms by 6%."] = "Healing Touch büyünün okuma süresini 0.3 sn azaltır ve tüm formlarda fiziksel saldırılarla verdiğin hasarı %6 artırır.",
   ["Reduces the cast time of your Healing Touch spell by 0.4 sec and increases the damage you deal with physical attacks in all forms by 8%."] = "Healing Touch büyünün okuma süresini 0.4 sn azaltır ve tüm formlarda fiziksel saldırılarla verdiğin hasarı %8 artırır.",
   ["Reduces the cast time of your Healing Touch spell by 0.5 sec and increases the damage you deal with physical attacks in all forms by 10%."] = "Healing Touch büyünün okuma süresini 0.5 sn azaltır ve tüm formlarda fiziksel saldırılarla verdiğin hasarı %10 artırır.",
   ["Reduces the cast time of your Lightning Bolt, Chain Lightning, and Lava Burst spells by 0.1 sec."] = "Lightning Bolt, Chain Lightning ve Lava Burst büyülerinin okuma süresini 0.1 sn azaltır.",
   ["Reduces the cast time of your Lightning Bolt, Chain Lightning, and Lava Burst spells by 0.2 sec."] = "Lightning Bolt, Chain Lightning ve Lava Burst büyülerinin okuma süresini 0.2 sn azaltır.",
   ["Reduces the cast time of your Lightning Bolt, Chain Lightning, and Lava Burst spells by 0.3 sec."] = "Lightning Bolt, Chain Lightning ve Lava Burst büyülerinin okuma süresini 0.3 sn azaltır.",
   ["Reduces the cast time of your Lightning Bolt, Chain Lightning, and Lava Burst spells by 0.4 sec."] = "Lightning Bolt, Chain Lightning ve Lava Burst büyülerinin okuma süresini 0.4 sn azaltır.",
   ["Reduces the cast time of your Lightning Bolt, Chain Lightning, and Lava Burst spells by 0.5 sec."] = "Lightning Bolt, Chain Lightning ve Lava Burst büyülerinin okuma süresini 0.5 sn azaltır.",
   ["Reduces the cast time of your Succubus' Seduction by 22%, and increases the duration of your Succubus' Seduction and Lesser Invisibility spells by 10%."] = "Succubus'unun Seduction büyüsünün okuma süresini %22 azaltır ve Succubus'unun Seduction ve Lesser Invisibility büyülerinin süresini %10 artırır.",
   ["Reduces the cast time of your Succubus' Seduction by 44%, and increases the duration of your Succubus' Seduction and Lesser Invisibility spells by 20%."] = "Succubus'unun Seduction büyüsünün okuma süresini %44 azaltır ve Succubus'unun Seduction ve Lesser Invisibility büyülerinin süresini %20 artırır.",
   ["Reduces the cast time of your Succubus' Seduction by 66%, and increases the duration of your Succubus' Seduction and Lesser Invisibility spells by 30%."] = "Succubus'unun Seduction büyüsünün okuma süresini %66 azaltır ve Succubus'unun Seduction ve Lesser Invisibility büyülerinin süresini %30 artırır.",
