   ["Reduces the chance you are critically hit by melee and ranged attacks by 1% and increases the threat reduction of your Feint ability by 10%."] = "Yakın dövüş ve menzilli saldırılarla kritik isabet alma şansını %1 azaltır ve Feint yeteneğinin tehdit azaltmasını %10 artırır.",
   ["Reduces the chance you are critically hit by melee and ranged attacks by 2% and increases the threat reduction of your Feint ability by 20%."] = "Yakın dövüş ve menzilli saldırılarla kritik isabet alma şansını %2 azaltır ve Feint yeteneğinin tehdit azaltmasını %20 artırır.",
   ["Reduces the chance you'll be critically hit by melee and spells by 1% and reduces all damage your summoned demon takes by 5%."] = "Yakın dövüş ve büyülerle kritik vurulma şansını %1 azaltır ve çağırdığın iblisin aldığı tüm hasarı %5 azaltır.",
   ["Reduces the chance you'll be critically hit by melee and spells by 2% and reduces all damage your summoned demon takes by 10%."] = "Yakın dövüş ve büyülerle kritik vurulma şansını %2 azaltır ve çağırdığın iblisin aldığı tüm hasarı %10 azaltır.",
   ["Reduces the chance you'll be critically hit by melee and spells by 3% and reduces all damage your summoned demon takes by 15%."] = "Yakın dövüş ve büyülerle kritik vurulma şansını %3 azaltır ve çağırdığın iblisin aldığı tüm hasarı %15 azaltır.",
   ["Reduces the chance you'll be hit by spells by 2% and when the ability is used it will reflect the first spell cast against the 2 closest party members within 20 yards."] = "Büyülerden vurulma şansını %2 azaltır ve yetenek kullanıldığında, 20 yard içindeki en yakın 2 grup üyesine yapılan ilk büyüyü yansıtır.",
   ["Reduces the chance you'll be hit by spells by 4% and when the ability is used it will reflect the first spell cast against the 4 closest party members within 20 yards."] = "Büyülerden vurulma şansını %4 azaltır ve yetenek kullanıldığında, 20 yard içindeki en yakın 4 grup üyesine yapılan ilk büyüyü yansıtır.",
   ["Reduces the chance your Feign Death ability and all trap spells will be resisted by 2%, and reduces the cooldown of your Disengage ability by 2 sec."] = "Feign Death yeteneğinin ve tüm tuzak büyülerinin direnilme şansını %2 azaltır ve Disengage yeteneğinin bekleme süresini 2 sn azaltır.",
   ["Reduces the chance your Feign Death ability and all trap spells will be resisted by 4%, and reduces the cooldown of your Disengage ability by 4 sec."] = "Feign Death yeteneğinin ve tüm tuzak büyülerinin direnilme şansını %4 azaltır ve Disengage yeteneğinin bekleme süresini 4 sn azaltır.",
   ["Reduces the chance your helpful spells and damage over time effects will be dispelled by 15% and reduces the threat caused by your Arcane spells by 20%."] = "Yardımcı büyülerinin ve zamanla hasar veren etkilerinin dağıtılma şansını %15 azaltır ve Arcane büyülerinin yarattığı tehdidi %20 azaltır.",
   ["Reduces the chance your helpful spells and damage over time effects will be dispelled by 30% and reduces the threat caused by your Arcane spells by 40%."] = "Yardımcı büyülerinin ve zamanla hasar veren etkilerinin dağıtılma şansını %30 azaltır ve Arcane büyülerinin yarattığı tehdidi %40 azaltır.",
   ["Reduces the cooldown by 10 sec and energy cost by 10 of your Tricks of the Trade, Distract and Shadowstep abilities and reduces the cooldown of Preparation by 3 min."] = "Tricks of the Trade, Distract ve Shadowstep yeteneklerinin bekleme süresini 10 sn ve enerji maliyetini 10 azaltır ve Preparation'ın bekleme süresini 3 dk azaltır.",
   ["Reduces the cooldown by 5 sec and energy cost by 5 of your Tricks of the Trade, Distract and Shadowstep abilities and reduces the cooldown of Preparation by 1.5 min."] = "Tricks of the Trade, Distract ve Shadowstep yeteneklerinin bekleme süresini 5 sn ve enerji maliyetini 5 azaltır ve Preparation'ın bekleme süresini 1.5 dk azaltır.",
